<!DOCTYPE html>
<html>
<head>
  <title>Maze Game</title>
  <style>
    body {
      font-family: sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
    }

    #maze {
      border: 1px solid black;
      width: 400px;
      height: 400px;
      margin: 20px;
    }

    .cell {
      width: 10px;
      height: 10px;
      position: absolute;
    }

    .wall-n {
      border-top: 1px solid black;
    }

    .wall-e {
      border-right: 1px solid black;
    }

    .wall-s {
      border-bottom: 1px solid black;
    }

    .wall-w {
      border-left: 1px solid black;
    }

    .bot {
      width: 8px;
      height: 8px;
      position: absolute;
      border-radius: 50%;
    }
  </style>
</head>
<body>
  <h1>Maze Game</h1>
  <div id="maze"></div>
  <div>
    <p>Completed: <span id="completed">0</span></p>
    <p>Timer: <span id="timer">0</span></p>
    <button id="reset">Reset</button>
  </div>

  <script>
    const mazeElement = document.getElementById('maze');
    const completedElement = document.getElementById('completed');
    const timerElement = document.getElementById('timer');
    const resetButton = document.getElementById('reset');

    const size = { rows: 25, cols: 25 }; // Minimum size for a solvable maze
    let elapsed = 0;
    let bots = [];
    let exit = null;
    let gameRunning = false;

    function generateMaze() {
      // Simple maze generation (can be improved)
      const maze = Array(size.rows).fill(null).map(() => Array(size.cols).fill(0));
      for (let r = 0; r < size.rows; r++) {
        for (let c = 0; c < size.cols; c++) {
          if ((r + c) % 2 === 0) {
            maze[r][c] = 1; // Wall
          } else {
            maze[r][c] = 0; // Passage
          }
        }
      }

      // Ensure entrance and exit
      maze[0][0] = 0;
      maze[size.rows - 1][size.cols - 1] = 0;
      exit = { r: size.rows - 1, c: size.cols - 1 };

      return maze;
    }


    function spawnBots() {
      bots = [];
      for (let i = 0; i < 24; i++) {
        const startRow = Math.floor(Math.random() * (size.rows - 2)) + 1;
        const startCol = Math.floor(Math.random() * (size.cols - 2)) + 1;
        bots.push({ r: startRow, c: startCol, path: [], deadEnds: [], finishTick: null });
      }
    }

    function drawMaze() {
      const cellSize = 10;
      for (let r = 0; r < size.rows; r++) {
        for (let c = 0; c < size.cols; c++) {
          const cell = document.createElement('div');
          cell.classList.add('cell');

          if (maze[r][c] === 1) {
            // Draw walls
            cell.classList.add(`wall-${['n', 'e', 's', 'w']}[${['n', 'e', 's', 'w'].indexOf(true)}]`);
          }

          mazeElement.appendChild(cell);
        }
      }
    }


    function drawBots() {
      bots.forEach(bot => {
        const botDiv = document.createElement('div');
        botDiv.classList.add('bot');
        botDiv.style.left = `${bot.c * cellSize}px`;
        botDiv.style.top = `${bot.r * cellSize}px`;

        mazeElement.appendChild(botDiv);
        bot.path.push({ r: bot.r, c: bot.c });
      });
    }


    function tick(n) {
      if (!gameRunning) return;
      elapsed++;
      timerElement.textContent = elapsed;

      for (let i = 0; i < bots.length; i++) {
        const bot = bots[i];
        if (bot.finishTick !== null) continue;

        const currentCell = { r: bot.r, c: bot.c };
        if (bot.path.some(cell => cell.r === bot.r && cell.c === bot.c)) continue; // Already visited

        let possibleMoves = [];
        if (maze[bot.r][bot.c] === 1) {
          // Check walls
          if (maze[bot.r + 1][bot.c] === 1) possibleMoves.push({ dr: 1, dc: 0, wall: 's' }); // Down
          if (maze[bot.r - 1][bot.c] === 1) possibleMoves.push({ dr: -1, dc: 0, wall: 'n' }); // Up
          if (maze[bot.r][bot.c + 1] === 1) possibleMoves.push({ dr: 0, dc: 1, wall: 'w' }); // Right
          if (maze[bot.r][bot.c - 1] === 1) possibleMoves.push({ dr: 0, dc: -1, wall: 'e' }); // Left
        } else {
          // No walls
          possibleMoves = [{ dr: 1, dc: 0, wall: null }, { dr: -1, dc: 0, wall: null }, { dr: 0, dc: 1, wall: null }, { dr: 0, dc: -1, wall: null }];
        }

        // Tremaux/DFS exploration with dead end marking
        let explored = new Set();
        for (const move of possibleMoves) {
          const nextR = bot.r + move.dr;
          const nextC = bot.c + move.dc;

          if (nextR >= 0 && nextR < size.rows && nextC >= 0 && nextC < size.cols && maze[nextR][nextC] === 0) {
            const nextCell = { r: nextR, c: nextC };
            if (!bot.path.some(cell => cell.r === nextR && cell.c === nextC)) {
              bot.path.push(nextCell);
              bot.r = nextR;
              bot.c = nextC;

              // Check for dead end
              let numWalls = 0;
              if (maze[bot.r + 1][bot.c] === 1) numWalls++;
              if (maze[bot.r - 1][bot.c] === 1) numWalls++;
              if (maze[bot.r][bot.c + 1] === 1) numWalls++;
              if (maze[bot.r][bot.c - 1] === 1) numWalls++;

              if (numWalls >= 3) {
                bot.deadEnds.push({ r: bot.r, c: bot.c });
              }

              // Recursively explore
              tick(1); // Recursive call to advance the simulation
            }
          }
        }
      }


      if (bots.every(bot => bot.finishTick !== null)) {
        completedElement.textContent = bots.length;
        gameRunning = false;
      }
    }

    function reset() {
      elapsed = 0;
      gameRunning = false;
      drawMaze();
      spawnBots();
      drawBots();
      timerElement.textContent = elapsed;
    }


    resetButton.addEventListener('click', reset);

    // Initialize the game
    window.game = {
      tick: tick,
      reset: reset,
      elapsed: elapsed,
      size: size,
      spawn: spawnBots,
      exit: exit,
      walls: (r, c) => maze[r][c] === 1,
      bots: bots
    };

    // Start the game
    gameRunning = true;
    spawnBots();
    drawMaze();
    drawBots();
  </script>
</body>
</html>
